# Top Python Coding Questions

# 1. Two Sum
def two_sum(nums, target):
    seen = {}
    for i, n in enumerate(nums):
        if target - n in seen:
            return [seen[target-n], i]
        seen[n] = i

print(f"Two Sum: {two_sum([2,7,11,15], 9)}")

# 2. Valid Parentheses
def is_valid(s):
    stack = []
    pairs = {')':'(', ']':'[', '}':'{'}
    for c in s:
        if c in '([{': stack.append(c)
        elif not stack or stack.pop() != pairs[c]: return False
    return not stack

print(f"Valid: {is_valid('()[]{}')}")

# 3. Fibonacci (memoized)
def fib(n, memo={}):
    if n <= 1: return n
    if n not in memo:
        memo[n] = fib(n-1) + fib(n-2)
    return memo[n]

print(f"Fib(10): {fib(10)}")
